import java.util.ArrayList;
import java.util.List;

public List<Integer> processQueries(int[] queries, int m) {
    List<Integer> nums = new ArrayList<>();
    List<Integer> result = new ArrayList<>();
    for (int i = 0; i < m; i++) {
        nums.add(i + 1);
    }
    for (int q : queries) {
        int pos = nums.indexOf(q);
        result.add(pos);
        nums.remove(pos);
        nums.add(0, q);
    }
    return result;
}
```

